VALUES
  ('social-worker-moex-02301', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '庫伯勒蘿思（Kübler-Ross）提出悲傷模式，認為一般人面對死亡階段，原則上是以下列那一種順序發展？ 否認－討價還價－沮喪－憤怒－接納  憤怒－否認－沮喪－討價還價－接納 否認－憤怒－討價還價－沮喪－接納  沮喪－否認－憤怒－討價還價－接納', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02302', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社工人員依據性別平等教育法及其相關法規之規定，對校園性別事件的處理與調查敘述，下列何者正確？ 社工人員在輔導受害人時，為維護受害人權益，應擔任調查小組成員 為了確認事件的真實性，調查小組、輔導團隊、行政處理人員都應該要反覆詢問相關當事人事件發生 的經過 校園性別事件的調查與處理應顧及受害學生的權益與感受，在其不願意繼續調查時，可以暫時擱置， 直到受害學生願意配合為止 調查小組以3人或5人為主，女性應占二分之一，且應有三分之一為主管單位認證之調查人才庫成員', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02303', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '玉珮在一家婦女福利機構工作 8 年多了，與她同期甚至更晚期進入機構的男同事都已經升遷擔任主管職 務，她在這次新任主管名單當中仍未獲拔擢。她深入分析主管性別後發現，近九成是男性。玉佩認為在 這個以服務婦女且工作人員多數是女性的社會福利機構，男性主管比例過高，是不公平的現象。這個機 構可能有何種現象？ 制度性歧視（institutional discrimination）  政黨政治運作 女性員工普遍無意願擔任主管職務  採「非性別主義」拔擢主管', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02304', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '發生校園霸凌狀況時，依據校園霸凌防制準則的規範，下列何者正確？ 依據該準則所稱之校園霸凌，僅限於發生於校園內的霸凌行為 學校面對被霸凌或曾有霸凌行為或傾向的學生，可以請家長帶回家中自行輔導與管教，不需進行處遇 疑似校園霸凌事件的被霸凌人可以向學校申請調查，學校應於3日內召開防制校園霸凌因應小組會議， 並於受理後2個月內處理完畢 媒體報導的疑似校園霸凌事件，因無申訴人，學校並不需要進行調查與處理', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02305', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '老人由於身心衰退，容易成為受虐待的族群，下列對老人生活與保護相關的敘述，何者錯誤？ 絕大多數的老人是在長期照顧機構中接受照顧 老人虐待的加害人（施虐者）可能是機構照顧人員，也可能是老人自己的親生子女 由於老人體力與靈活度降低，容易成為搶劫、詐騙等犯罪的被害者 通報老人受虐人數與實際受虐人數相較，可能只是冰山之一角', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02306', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於性別影響評估的敘述，何者錯誤？ 在規劃法案、政策、計畫、方案、策略時，將「性別」當作一個必要元素 考量不同年齡族群的觀點及對各類人際關係發展的影響 行政院各機關之中長程個案計畫及法案，均需進行性別影響評估 性別影響評估係由一系列問題所組成的測量工具', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02307', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於Piaget的認知發展理論的描述，何者正確？ 依照年齡分為八個階段，人在對應的年齡就會自然進入該階段 2到7歲的兒童認知發展為感覺動作期，兒童可以透過感官經驗來探索世界 國小階段（7到11歲）的兒童認知發展為運思前期，兒童可以透過抽象概念來進行思考 12歲以上青少年的認知發展在形式運思期，具有可以學習數學代數、幾何等抽象邏輯推理能力', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02308', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '物質濫用對人類行為及生活產生嚴重的影響，常被濫用的物質包括鎮定劑、安定劑、止痛劑及興奮劑， 下列那一種物質不屬於興奮劑的作用？ 酒精  安非他命  大麻  海洛因', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02309', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會存在貧窮及收入在貧窮線（poverty line）以下的問題，下列對「貧窮」的敘述，何者錯誤？ 大多數的貧窮或窮人都是因為個人的能力低落或努力不足而造成 社會上的性別歧視可能導致貧窮 貧窮可能一代一代傳遞，成為貧窮惡性循環 某些功能主義學者認為貧窮具有一定的功能，如果沒有窮人，一些卑微艱苦的工作就沒有人去做了', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02310', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '同性戀者從認知自己的性取向到公開承認同性戀傾向的過程為「出櫃」。一般而言，出櫃需要歷經四個 階段，其順序為何？ 認識圈內人－自我坦承－向親友坦承－出櫃  自我坦承－認識圈內人－向親友坦承－出櫃 認識圈內人－向親友坦承－自我坦承－出櫃  自我坦承－向親友坦承－認識圈內人－出櫃', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
